INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 0, 0.029, 105, 101, 160, 1.5, 1, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 122601, 0, 1, 110, 1);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (3, 0, 0.014, 111, 102, 120, 2.5, 0, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 122401, 1, 2, 105, 2);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 1, 0.017, 105, 103, 350, 2.5, 0, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 122501, 0, 3, 110, 3);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (3, 0, 0.016, 105, 104, 130, 1.5, 0, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 107501, 1, 4, 110, 4);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 0, 0.014, 105, 105, 160, 2.5, 1, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 107601, 0, 5, 110, 5);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 1, 0.029, 103, 106, 255, 3.5, 0, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 107801, 0, 6, 120, 6);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 0, 0.013, 103, 107, 160, 3.5, 1, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 110601, 0, 7, 120, 7);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 1, 0.014, 103, 108, 350, 2.5, 0, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 110401, 0, 8, 110, 8);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (3, 0, 0.012, 100, 109, 130, 1.5, 0, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 110501, 1, 9, 105, 9);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 0, 0.014, 103, 110, 200, 2.5, 1, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 115701, 0, 10, 105, 10);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 1, 0.071, 103, 111, 350, 2.5, 0, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 113601, 0, 11, 105, 11);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (3, 0, 0.014, 103, 112, 130, 1.5, 0, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 107901, 1, 12, 120, 12);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 0, 0.022, 105, 113, 200, 1.5, 1, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 108001, 0, 13, 110, 13);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 0, 0.031, 108, 114, 160, 2.5, 1, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 110301, 0, 14, 110, 14);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 0, 0.036, 105, 115, 130, 0.5, 0, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 107701, 1, 15, 110, 15);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 1, 0.048, 95, 116, 350, 3.5, 0, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 113101, 0, 16, 110, 16);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (3, 0, 0.043, 105, 117, 130, 1.5, 0, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 113301, 1, 17, 105, 17);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 0, 0.018, 95, 118, 130, 1.5, 0, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 113201, 1, 18, 105, 18);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 0, 0.021, 108, 119, 160, 2.5, 1, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 117001, 0, 19, 110, 19);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 1, 0.036, 105, 120, 255, 2.5, 0, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 113501, 0, 20, 110, 20);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (3, 1, 0.02, 105, 121, 350, 2.5, 0, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 113401, 0, 21, 105, 21);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 0, 0.018, 105, 122, 130, 2.5, 0, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 110101, 1, 22, 110, 22);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (3, 0, 0.03, 111, 123, 160, 3.5, 1, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 110001, 0, 23, 105, 23);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 0, 0.027, 103, 124, 130, 1.5, 0, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 117201, 1, 24, 110, 24);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 0, 0.02, 108, 125, 160, 3.5, 1, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 117301, 0, 25, 105, 25);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (3, 1, 0.04, 105, 126, 350, 2.5, 0, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 117401, 0, 26, 110, 26);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 1, 0.009, 105, 127, 350, 3.5, 0, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 117101, 0, 27, 110, 27);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 1, 0.022, 105, 128, 255, 3.5, 0, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 122901, 0, 28, 120, 28);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (3, 0, 0.028, 105, 129, 130, 2.5, 0, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 122801, 1, 29, 110, 29);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 0, 0.023, 108, 130, 130, 3.5, 1, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 122701, 0, 30, 105, 30);
